"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[364],{247:e=>{e.exports=JSON.parse('{"functions":[{"name":"State","desc":"Creates a new reactive `State` object that can be bound to GUI updates. Call `Set` on\\nthe returned object to update the state and trigger UI updates.\\n\\n```lua\\nlocal coins: Flux.State<number> = Flux:State(0)\\ncontroller:Bind(coins, function(n: number) label.Text = tostring(n) end)\\ncoins:Set(42)\\n```","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"initialValue","desc":"An optional starting value","lua_type":"T?"}],"returns":[{"desc":"","lua_type":"State<T>"}],"function_type":"static","source":{"line":102,"path":"src/Flux/init.luau"}},{"name":"MountScreenGui","desc":"Parents the given `ScreenGui` to the local player\'s `PlayerGui` and returns a `Controller`\\nthat owns its lifecycle. The caller is responsible for cloning templates before passing them in.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"gui","desc":"The GUI instance to mount","lua_type":"ScreenGui"}],"returns":[{"desc":"","lua_type":"Controller"}],"function_type":"static","source":{"line":113,"path":"src/Flux/init.luau"}},{"name":"MountSurfaceGui","desc":"Sets the `Adornee` (and optionally `Face`) on the given `SurfaceGui`, parents it to the local\\nplayer\'s `PlayerGui`, and returns a `Controller` that owns its lifecycle. The caller is\\nresponsible for cloning templates before passing them in.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"gui","desc":"The GUI instance to mount","lua_type":"SurfaceGui"},{"name":"adornee","desc":"The part the SurfaceGui will be attached to","lua_type":"BasePart"},{"name":"face","desc":"The face of the part the SurfaceGui will be attached to (optional)","lua_type":"Enum.NormalId?"}],"returns":[{"desc":"","lua_type":"Controller"}],"function_type":"static","source":{"line":128,"path":"src/Flux/init.luau"}},{"name":"MountBillboardGui","desc":"Sets the `Adornee` on the given `BillboardGui`, parents it to the local player\'s `PlayerGui`,\\nand returns a `Controller` that owns its lifecycle. The caller is responsible for cloning\\ntemplates before passing them in.","params":[{"name":"_self","desc":"","lua_type":"Flux"},{"name":"gui","desc":"The GUI instance to mount","lua_type":"BillboardGui"},{"name":"adornee","desc":"The part the BillboardGui will be attached to","lua_type":"BasePart"}],"returns":[{"desc":"","lua_type":"Controller"}],"function_type":"static","source":{"line":146,"path":"src/Flux/init.luau"}}],"properties":[],"types":[{"name":"Scope","desc":"A minimal lifecycle scope passed to each component function. Use `Bind` to subscribe to reactive state\\nand `Mount` to compose child components. All bindings and child mounts made through this scope are\\nautomatically cleaned up when the parent GUI is unmounted.","fields":[{"name":"Bind","lua_type":"(self, state: State<T>, callback: (newValue: T?) -> ()) -> ()","desc":"Binds to a `State` scoped to this component\'s lifecycle"},{"name":"Mount","lua_type":"(self, component: Component, instance: Instance, props: {[string]: any}?) -> ()","desc":"Mounts a child component scoped to this component\'s lifecycle"}],"source":{"line":16,"path":"src/Flux/init.luau"}},{"name":"Component","desc":"A reusable function that applies behavior to a GUI child `Instance`. Components are mounted to a specific\\n`Instance` in the GUI hierarchy and can bind to reactive state using the provided `Scope`. Components\\nshould be used for reusable pieces of UI behavior. For example, you might have a \\"HealthBar\\" component that\\nyou mount to any Frame to turn it into a health bar, or a \\"Draggable\\" component that makes any GUI element\\ndraggable. Components should not manage the lifecycle of their own `Instance` (i.e. by destroying it or\\nreparenting it), they should only be responsible for updating the instance\'s properties in response to state changes,\\npassed down through `props` or observed via `Bind`. Let the parent `Controller` manage the lifecycle of all instances.","lua_type":"(instance: Instance, scope: Scope, props: {[string]: any}?) -> ()","source":{"line":30,"path":"src/Flux/init.luau"}},{"name":"State","desc":"A reactive state object. Create these using `Flux:State` and pass them to\\n`Controller:Bind` or `Scope:Bind` inside components to reactively drive UI updates.","source":{"line":39,"path":"src/Flux/init.luau"}},{"name":"Self","desc":"","lua_type":"Flux","source":{"line":52,"path":"src/Flux/init.luau"}}],"name":"Flux","desc":"Client module for mounting and managing GUI instances. Each mount parents the GUI to\\n`PlayerGui` and returns a `Controller` that owns the instance\'s lifecycle.\\nThe caller is responsible for cloning templates before passing them in.\\n\\n```lua\\nlocal Flux = require(ReplicatedStorage.Flux)\\n\\n-- Create reactive state\\nlocal coins: Flux.State<number> = Flux:State(0)\\n\\n-- Clone and mount the GUI\\nlocal gui = ReplicatedStorage.Assets.Gui.CoinScreenGui:Clone()\\nlocal controller = Flux:MountScreenGui(gui)\\n\\n-- Bind state to UI\\ncontroller:Bind(coins, function(count: number)\\n\\tlocal frame = controller:GetInstance():FindFirstChild(\\"Frame\\")\\n\\tif frame then\\n\\t\\tlocal coinsLabel = frame:FindFirstChild(\\"CoinsLabel\\")\\n\\t\\tif coinsLabel and coinsLabel:IsA(\\"TextLabel\\") then\\n\\t\\t\\tcoinsLabel.Text = tostring(count)\\n\\t\\tend\\n\\tend\\nend)\\n\\n-- Update state from gameplay\\ncoins:Set(42)\\n```","source":{"line":87,"path":"src/Flux/init.luau"}}')}}]);